class Solution {
public:
    bool digitCount(string num) {
        for (int i = 0; i < num.size(); i++) {
            int count = 0;
            for (char c : num) {
                if (c - '0' == i) {
                    count++;
                }
            }
            if (count != num[i] - '0') {
                return false;
            }
        }
        return true;
    }
};
